external_knowledge:
- 'Versatile components' refers to components used in more than one board; 
- 'Highest demand' refers to the components with the highest total quantity used; 
- 'Currently in stock' refers to components with a positive quantity in the inventory.

sql:
SELECT component_name
FROM components
ORDER BY component_name;

SELECT board_name
FROM boards
WHERE status = 'design';

SELECT board_name
FROM boards
WHERE board_id = 0;

SELECT component_name 
FROM components 
ORDER BY component_name;

SELECT SUM(quantity_used) AS total_quantity_used
FROM component_usage
WHERE component_id = 1;

SELECT location
FROM component_usage
WHERE component_id = 1 AND board_id = 1;

SELECT SUM(quantity_used) AS total_quantity_used
FROM component_usage
WHERE component_id = 1;

SELECT board_name 
FROM boards 
ORDER BY board_name;
